def live(command):
    """Executes a command and prints output in real time"""
    process = subprocess.Popen(
        command, shell=True, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True
    )
    output = []
    for line in process.stdout:
        print(line, end="")
        output.append(line)
    process.wait()
    return "".join(output)
